# routing_advisor.py — Claude Code output
import sys

def route(desc):
    d = desc.lower()
    if 'delete' in d or 'deploy' in d:
        return 'human-only', 'irreversible action'
    if 'repo' in d or 'code' in d:
        return 'claude-code', 'context_source=repo'
    if 'folder' in d or 'file' in d:
        return 'claude-cowork', 'context_source=filesystem'
    return 'claude-ai', 'context_source=conversation'

if __name__ == '__main__':
    desc = sys.stdin.read()
    surface, factor = route(desc)
    print(f'Surface: {surface}\nFactor:  {factor}')
